PB.D21_vals = D21_vals;
PB.D23_vals = D23_vals;
PB.K24_labels = K24_labels; PB.K24_embed = K24_embed;
PB.K26_labels = K26_labels; PB.K26_embed = K26_embed;
PB.D27_vals = D27_vals;
PB.D29_vals = D29_vals;
PB.K30_labels = K30_labels; PB.K30_embed = K30_embed;
PB.pareto_front_known = true;
PB.pareto_set_known = true;
PB.pf_type = 'concave';
PB.ideal_point = [0;0];
PB.nadir_point = [1;1];
PB.core = @(xh) ZDT2_orig(xh);
PB.decode = @(xr) decode(xr, PB);
PB.func_F = @(xr) objective(xr, PB);
PB_cached = PB;
else
    PB = PB_cached;
end

if nargin == 0
    varargout{1} = PB; return
end
arg1 = varargin{1};
if ischar(arg1) || (isstring(arg1) && isscalar(arg1))
    key = lower(char(arg1));
    switch key
        case {'problemdata','bounds','domain'}
            varargout{1} = PB.ProblemData; return
        case 'var_types'
            varargout{1} = PB.var_types; return
        case 'info'
            varargout{1} = PB; return
        otherwise
            error('Unknown string argument: %s', char(arg1));
    end
end
varargout{1} = PB.func_F(arg1);
end

function F = objective(xr, PB)
xh = decode(xr, PB);
F = PB.core(xh);
F = F(:);
end

function xh = decode(xr, PB)
if ~iscell(xr) || numel(xr) ~= 30
    error('ZDT2_mix: input must be a cell array with exactly 30 entries.');
end
xh = zeros(30,1);
tmp = check_C(xr{1}, PB.lb_C_work(1), PB.ub_C_work(1), 'x1');
xh(1) = map_C_to_orig(tmp, PB.lb_C_work(1), PB.ub_C_work(1), PB.lb_orig(1), PB.ub_orig(1));
xh(2) = check_K(xr{2}, PB.K2_labels, PB.K2_embed, 'x2');
xh(3) = check_D(xr{3}, PB.D3_vals, 'x3');
tmp = check_C(xr{4}, PB.lb_C_work(4), PB.ub_C_work(4), 'x4');
xh(4) = map_C_to_orig(tmp, PB.lb_C_work(4), PB.ub_C_work(4), PB.lb_orig(4), PB.ub_orig(4));
xh(5) = check_D(xr{5}, PB.D5_vals, 'x5');
xh(6) = check_K(xr{6}, PB.K6_labels, PB.K6_embed, 'x6');
tmp = check_C(xr{7}, PB.lb_C_work(7), PB.ub_C_work(7), 'x7');
xh(7) = map_C_to_orig(tmp, PB.lb_C_work(7), PB.ub_C_work(7), PB.lb_orig(7), PB.ub_orig(7));
xh(8) = check_K(xr{8}, PB.K8_labels, PB.K8_embed, 'x8');
xh(9) = check_D(xr{9}, PB.D9_vals, 'x9');
tmp = check_C(xr{10}, PB.lb_C_work(10), PB.ub_C_work(10), 'x10');
xh(10) = map_C_to_orig(tmp, PB.lb_C_work(10), PB.ub_C_work(10), PB.lb_orig(10), PB.ub_orig(10));
xh(11) = check_D(xr{11}, PB.D11_vals, 'x11');
xh(12) = check_K(xr{12}, PB.K12_labels, PB.K12_embed, 'x12');
tmp = check_C(xr{13}, PB.lb_C_work(13), PB.ub_C_work(13), 'x13');
xh(13) = map_C_to_orig(tmp, PB.lb_C_work(13), PB.ub_C_work(13), PB.lb_orig(13), PB.ub_orig(13));
xh(14) = check_K(xr{14}, PB.K14_labels, PB.K14_embed, 'x14');
xh(15) = check_D(xr{15}, PB.D15_vals, 'x15');
tmp = check_C(xr{16}, PB.lb_C_work(16), PB.ub_C_work(16), 'x16');
xh(16) = map_C_to_orig(tmp, PB.lb_C_work(16), PB.ub_C_work(16), PB.lb_orig(16), PB.ub_orig(16));
xh(17) = check_D(xr{17}, PB.D17_vals, 'x17');
xh(18) = check_K(xr{18}, PB.K18_labels, PB.K18_embed, 'x18');
tmp = check_C(xr{19}, PB.lb_C_work(19), PB.ub_C_work(19), 'x19');
xh(19) = map_C_to_orig(tmp, PB.lb_C_work(19), PB.ub_C_work(19), PB.lb_orig(19), PB.ub_orig(19));
xh(20) = check_K(xr{20}, PB.K20_labels, PB.K20_embed, 'x20');
xh(21) = check_D(xr{21}, PB.D21_vals, 'x21');
tmp = check_C(xr{22}, PB.lb_C_work(22), PB.ub_C_work(22), 'x22');
xh(22) = map_C_to_orig(tmp, PB.lb_C_work(22), PB.ub_C_work(22), PB.lb_orig(22), PB.ub_orig(22));
xh(23) = check_D(xr{23}, PB.D23_vals, 'x23');
xh(24) = check_K(xr{24}, PB.K24_labels, PB.K24_embed, 'x24');
tmp = check_C(xr{25}, PB.lb_C_work(25), PB.ub_C_work(25), 'x25');
xh(25) = map_C_to_orig(tmp, PB.lb_C_work(25), PB.ub_C_work(25), PB.lb_orig(25), PB.ub_orig(25));
xh(26) = check_K(xr{26}, PB.K26_labels, PB.K26_embed, 'x26');
xh(27) = check_D(xr{27}, PB.D27_vals, 'x27');
tmp = check_C(xr{28}, PB.lb_C_work(28), PB.ub_C_work(28), 'x28');
xh(28) = map_C_to_orig(tmp, PB.lb_C_work(28), PB.ub_C_work(28), PB.lb_orig(28), PB.ub_orig(28));
xh(29) = check_D(xr{29}, PB.D29_vals, 'x29');
xh(30) = check_K(xr{30}, PB.K30_labels, PB.K30_embed, 'x30');
end

function v = check_C(val, a, b, name)
if ~isnumeric(val) || ~isscalar(val) || ~isreal(val)
    error('ZDT2_mix: %s must be a real scalar.', name);
end
if val < a || val > b
    error('ZDT2_mix: %s=%g outside [%g,%g].', name, val, a, b);
end
v = double(val);
end

function xorig = map_C_to_orig(xwork, lbw, ubw, lbo, ubo)
if abs(ubw - lbw) <= 1e-14
    t = 0;
else
    t = (xwork - lbw) / (ubw - lbw);
end
t = max(0, min(1, t));
xorig = lbo + t * (ubo - lbo);
end

function v = check_D(val, grid, name)
if ~isnumeric(val) || ~isscalar(val) || ~isreal(val)
    error('ZDT2_mix: %s must be a real scalar.', name);
end
grid = grid(:);
[dmin, idx] = min(abs(grid - val));
if dmin > 1e-10 * max(1, max(abs(grid)))
    error('ZDT2_mix: %s=%g not in grid.', name, val);
end
v = grid(idx);
end

function v = check_K(label, labels, embed, name)
if isstring(label), label = char(label); end
if ~(ischar(label) && isrow(label))
    error('ZDT2_mix: %s must be a char vector or scalar string.', name);
end
idx = find(strcmp(label, labels), 1);
if isempty(idx)
    error('ZDT2_mix: %s unknown label ''%s''.', name, label);
end
v = embed(idx);
end


% -------------------------------------------------------------------------
% Embedded original continuous MOO problem (top-level function renamed only)
% -------------------------------------------------------------------------
function f = ZDT2_orig(x)
% ZDT2 function
%
%   As described by E. Zitzler, K. Deb, and L. Thiele in "Comparison of
%   Multiobjective Evolutionary Algorithms: Empirical Results", Evolutionary 
%   Computation 8(2): 173-195, 2000
%
%   Example T2.
%
%   This file is part of a collection of problems developed for
%   derivative-free multiobjective optimization in
%   A. L. Custódio, J. F. A. Madeira, A. I. F. Vaz, and L. N. Vicente,
%   Direct Multisearch for Multiobjective Optimization, 2010.
%
%   Written by the authors in June 1, 2010.
%   Adapted to MATLAB format in November 2025.
%
%   Input: x is a m-dimensional vector, where m = 30
%
%   Problem characteristics:
%   m = 30 variables; 2 objectives.
%   Bounds: x1 in [0,1], x2 in [0,1], x3 in [0,1], x4 in [0,1], x5 in [0,1], x6 in [0,1], x7 in [0,1], x8 in [0,1], x9 in [0,1], x10 in [0,1], x11 in [0,1], x12 in [0,1], x13 in [0,1], x14 in [0,1], x15 in [0,1], x16 in [0,1], x17 in [0,1], x18 in [0,1], x19 in [0,1], x20 in [0,1], x21 in [0,1], x22 in [0,1], x23 in [0,1], x24 in [0,1], x25 in [0,1], x26 in [0,1], x27 in [0,1], x28 in [0,1], x29 in [0,1], x30 in [0,1]
%
%   Output: f is a 2-dimensional vector with the function values
%          handled by the optimization algorithm)
% Número de variáveis
m = 30;
% Função objetivo 1
f1 = x(1);
% Cálculo de g(x)
gx = 1 + 9/(m-1) * sum(x(2:m));
% Cálculo de h - Note a diferença em relação ao ZDT1: aqui usa (f1/gx)^2
h = 1 - (f1/gx)^2;
% Função objetivo 2
f2 = gx * h;
% Vetor de funções objetivo
f = [f1; f2];
end

